public class ArrayRotation {
    public static void rotateArray(int[] arr, int n) {
        int[] temp = new int[arr.length];
        int len = arr.length;

        // Copy the last 'n' elements to the beginning of the temporary array
        for (int i = 0; i < n; i++) {
            temp[i] = arr[len - n + i];
        }

        // Copy the remaining elements to the end of the temporary array
        for (int i = n; i < len; i++) {
            temp[i] = arr[i - n];
        }

        // Copy the rotated array back to the original array
        for (int i = 0; i < len; i++) {
            arr[i] = temp[i];
        }
    }

    public static void printArray(int[] arr) {
